import{_ as a,o as i,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Bedrijfspagina","description":"","frontmatter":{},"headers":[],"relativePath":"nl/advanced/business-page.md","filePath":"nl/advanced/business-page.md"}'),t={name:"nl/advanced/business-page.md"};function s(l,e,o,d,g,p){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="bedrijfspagina" tabindex="-1">Bedrijfspagina <a class="header-anchor" href="#bedrijfspagina" aria-label="Permalink to &quot;Bedrijfspagina&quot;">​</a></h1><p>Maak een openbaar profiel voor je bedrijf dat klanten kunnen bezoeken om meer te weten te komen over je diensten en offertes aan te vragen.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>Je bedrijfspagina is een openbare webpagina die het volgende toont:</p><ul><li>Je bedrijfsinformatie</li><li>Diensten die je aanbiedt</li><li>Contactgegevens</li><li>Social media-links</li><li>Een offerteaanvraagformulier</li></ul><h2 id="je-bedrijfspagina-instellen" tabindex="-1">Je bedrijfspagina instellen <a class="header-anchor" href="#je-bedrijfspagina-instellen" aria-label="Permalink to &quot;Je bedrijfspagina instellen&quot;">​</a></h2><ol><li>Ga naar <strong>Bedrijf</strong>-instellingen</li><li>Vul het gedeelte <strong>bedrijfsprofiel</strong> in: <ul><li><strong>Beschrijving</strong> — Een kort overzicht van je bedrijf</li><li><strong>Diensten</strong> — Vermeld de diensten die je aanbiedt</li><li><strong>Website</strong> — De URL van je bedrijfswebsite</li><li><strong>Social media</strong> — Links naar je sociale profielen</li></ul></li><li>Je bedrijfspagina is automatisch beschikbaar op een unieke URL</li></ol><h2 id="bedrijfspagina-url" tabindex="-1">Bedrijfspagina-URL <a class="header-anchor" href="#bedrijfspagina-url" aria-label="Permalink to &quot;Bedrijfspagina-URL&quot;">​</a></h2><p>Je pagina is bereikbaar op:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://app.mycompanydesk.com/portal/{jouw-bedrijfs-slug}</span></span></code></pre></div><p>Deel deze link op je website, social media of visitekaartjes.</p><h2 id="offerteaanvraagformulier" tabindex="-1">Offerteaanvraagformulier <a class="header-anchor" href="#offerteaanvraagformulier" aria-label="Permalink to &quot;Offerteaanvraagformulier&quot;">​</a></h2><p>Bezoekers van je bedrijfspagina kunnen een offerteaanvraag indienen:</p><ol><li>Ze vullen hun <strong>naam</strong>, <strong>e-mail</strong> en <strong>dienstomschrijving</strong> in</li><li>De aanvraag wordt ingediend</li><li>Je ontvangt een melding</li><li>De aanvraag verschijnt in <strong>Offertes &gt; Aanvragen</strong></li></ol><h3 id="snelheidslimiet" tabindex="-1">Snelheidslimiet <a class="header-anchor" href="#snelheidslimiet" aria-label="Permalink to &quot;Snelheidslimiet&quot;">​</a></h3><p>Om spam te voorkomen zijn offerteaanvragen beperkt tot 1 per 15 minuten per IP-adres.</p><h2 id="aanvragen-beheren" tabindex="-1">Aanvragen beheren <a class="header-anchor" href="#aanvragen-beheren" aria-label="Permalink to &quot;Aanvragen beheren&quot;">​</a></h2><p>Zie <a href="/nl/features/quotes#offerteaanvragen">Offertes — Offerteaanvragen</a> voor details over het beheren van binnenkomende aanvragen.</p><h2 id="huisstijl" tabindex="-1">Huisstijl <a class="header-anchor" href="#huisstijl" aria-label="Permalink to &quot;Huisstijl&quot;">​</a></h2><p>Je bedrijfspagina gebruikt je bedrijfshuisstijl:</p><ul><li>Bedrijfslogo</li><li>Accentkleur</li><li>Bedrijfsnaam en -gegevens</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Houd je dienstenaanbod up-to-date</li><li>Voeg een link naar je bedrijfspagina toe op je website</li><li>Reageer snel op offerteaanvragen voor betere conversie</li><li>Gebruik de offerteaanvraagworkflow om leads bij te houden</li></ul>',23)])])}const b=a(t,[["render",s]]);export{h as __pageData,b as default};
